/**
 * GET /api/v1/problems/:problemId
 * Returns problem detail with component statistics or 404 if not found
 */
async function getProblemDetail(req, res) {
	const problemId = req.params.problemId;
	const detail = ProblemsService.getProblemDetail(problemId);
	if (!detail) {
		return res.status(404).json({ error: `Problem with id '${problemId}' not found` });
	}
	return res.json(detail);
}

module.exports = {
	getProblemDetail
};
